<script lang="ts">
	import { onMount } from 'svelte';

	let { progress = 0 } = $props();

	let paths: SVGPathElement[] = $state([]);
	let pathLengths = $state<number[]>([]);

	onMount(() => {
		pathLengths = paths.map(path => path.getTotalLength());
	});

	// Split progress among paths
	// Path 0 (Outline): 0.0 -> 0.4
	// Paths 1-4 (Details): 0.4 -> 1.0 (sequential or parallel)
	function getPathProgress(index: number, totalProgress: number) {
		const segments = [0, 0.4, 0.55, 0.7, 0.85, 1.0];
		const start = segments[index];
		const end = segments[index + 1];
		
		if (totalProgress <= start) return 0;
		if (totalProgress >= end) return 1;
		
		return (totalProgress - start) / (end - start);
	}

	// For filling, we want a smoother transition that starts after the stroke is partially done
	function getFillOpacity(index: number, totalProgress: number) {
		const p = getPathProgress(index, totalProgress);
		return p; // Linear mapping for now
	}
</script>

